<template><div class="page-container"><div class="page-header"><div><h1>审批中心</h1><p class="subtitle">待办和已办均以服务端数据范围为准。</p></div></div><el-tabs v-model="tab" @tab-change="load"><el-tab-pane label="待办审批" name="pending"><ApprovalTable :rows="rows" :loading="loading" @view="view" /></el-tab-pane><el-tab-pane label="已办审批" name="processed"><ApprovalTable :rows="rows" :loading="loading" @view="view" /></el-tab-pane></el-tabs></div></template>
<script setup>
import { ref, watch } from 'vue'; import { useRoute, useRouter } from 'vue-router'; import { getPendingApprovals, getProcessedApprovals } from '../../api/approvals'; import StatusTag from '../../components/common/StatusTag.vue'; import { formatDateTime } from '../../utils/date'
const route=useRoute();const router=useRouter();const tab=ref(route.query.tab==='processed'?'processed':'pending');const rows=ref([]);const loading=ref(false);async function load(){loading.value=true;try{rows.value=tab.value==='pending'?await getPendingApprovals():await getProcessedApprovals();router.replace({query:{tab:tab.value}})}finally{loading.value=false}}function view(row){router.push(`/approvals/${row.approvalId}`)}watch(tab,load,{immediate:true})
const ApprovalTable={props:['rows','loading'],emits:['view'],components:{StatusTag},methods:{formatDateTime},template:`<el-table :data="rows" v-loading="loading" border stripe><el-table-column prop="approvalNo" label="审批编号" width="180"/><el-table-column prop="applicationNo" label="申请编号" width="180"/><el-table-column prop="title" label="申请标题" min-width="180" show-overflow-tooltip/><el-table-column prop="applicantName" label="申请人" width="120"/><el-table-column label="状态" width="120"><template #default="{row}"><StatusTag :value="row.status" kind="approval"/></template></el-table-column><el-table-column label="提交时间" min-width="170"><template #default="{row}">{{formatDateTime(row.submittedAt)}}</template></el-table-column><el-table-column label="操作" width="90" fixed="right"><template #default="{row}"><el-button link type="primary" @click="$emit('view',row)">查看</el-button></template></el-table-column></el-table>`}
</script>
<style scoped>.page-container{display:flex;flex-direction:column;gap:16px}.page-header h1{margin:0 0 8px}.subtitle{margin:0;color:var(--el-text-color-secondary)}</style>
